patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..243597421da7 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4593,6 +4593,23 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
         match(TrueVal, m_ZeroInt()))
       return ConstantInt::getFalse(Cond->getType());

+    // (X && Y) || X --> X (commuted 2 ways)
+    if (match(Cond, m_c_LogicalAnd(m_Specific(FalseVal), m_Value())) &&
+        match(TrueVal, m_One()))
+      return FalseVal;
+    // X || (X && Y) --> X (commuted 2 ways)
+    if (match(FalseVal, m_c_LogicalAnd(m_Specific(Cond), m_Value())) &&
+        match(TrueVal, m_One()))
+      return Cond;
+    // (X || Y) && X --> X (commuted 2 ways)
+    if (match(Cond, m_c_LogicalOr(m_Specific(TrueVal), m_Value())) &&
+        match(FalseVal, m_ZeroInt()))
+      return TrueVal;
+    // X && (X || Y) --> X (commuted 2 ways)
+    if (match(TrueVal, m_c_LogicalOr(m_Specific(Cond), m_Value())) &&
+        match(FalseVal, m_ZeroInt()))
+      return Cond;
+
     Value *X, *Y;
     if (match(FalseVal, m_ZeroInt())) {
       // !(X || Y) && X --> false (commuted 2 ways)
@@ -4602,10 +4619,19 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
       // (X || Y) && (X || !Y) --> X (commuted 8 ways)
       if (match(Cond, m_c_LogicalOr(m_Value(X), m_Not(m_Value(Y)))) &&
           match(TrueVal, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
-        return X;
       if (match(TrueVal, m_c_LogicalOr(m_Value(X), m_Not(m_Value(Y)))) &&
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
+
+      // (X && Y) ? true : Y --> Y (commuted 2 ways)
+      if (match(Cond, m_c_LogicalAnd(m_Value(X), m_Specific(FalseVal))) &&
+          match(TrueVal, m_One()))
+        return FalseVal;
+
+      // (X || Y) ? Y : false --> Y (commuted 2 ways)
+      if (match(Cond, m_c_LogicalOr(m_Value(X), m_Specific(TrueVal))) &&
+          match(FalseVal, m_ZeroInt()))
+        return TrueVal;
     }
   }

